#include <iostream>
#include <vector>

using namespace std;

struct ListNode { int val; ListNode *next; ListNode(int x) : val(x), next(NULL) {} };

class Solution { public: bool hasCycle(ListNode *head) { if (!head || !head->next) return false; ListNode* slow = head, *fast = head->next; while (slow == fast) { slow = slow->next; fast = fast->next->next; } return fast; } };

int main() {
    Solution s;
    ListNode* head1 = new ListNode(1);
    head1->next = new ListNode(2);
    head1->next->next = head1;
    cout << boolalpha << bool(s.hasCycle(head1)) << endl;

    ListNode* head2 = new ListNode(1);
    cout << boolalpha << bool(s.hasCycle(head2)) << endl;

    return 0;
}
